import java.time.Duration;
import java.util.Collections;
import java.util.Properties;

import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;

/**
 * A Kafka consumer that consumes messages from the "inventory-updates" topic
 * and processes them idempotently.
 *
 * This consumer follows Apache Kafka ecosystem patterns:
 * - Uses ConsumerConfig constants for configuration keys
 * - Implements consumer loop using poll(Duration) API
 * - Commits offsets synchronously after processing each batch
 * - Handles WakeupException for clean shutdown
 */
public class InventoryConsumer {
    private final KafkaConsumer<String, String> consumer;
    private volatile boolean closed = false;

    public InventoryConsumer(String bootstrapServers, String groupId) {
        Properties props = new Properties();

        // Use ConsumerConfig constants for all configuration keys
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);

        // Disable auto-commit to enable manual offset management
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, false);

        // Set auto offset reset policy
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");

        this.consumer = new KafkaConsumer<>(props);
    }

    /**
     * Start consuming messages from the inventory-updates topic.
     * This method runs the consumer loop and processes messages idempotently.
     */
    public void start() {
        try {
            // Subscribe to the inventory-updates topic
            consumer.subscribe(Collections.singletonList("inventory-updates"));

            // Consumer loop using poll(Duration) API
            while (!closed) {
                try {
                    // Poll for records with a timeout of 1 second
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofSeconds(1));

                    // Process each record idempotently
                    for (ConsumerRecord<String, String> record : records) {
                        processRecord(record);
                    }

                    // Commit offsets synchronously after processing each batch
                    if (records.count() > 0) {
                        consumer.commitSync();
                    }
                } catch (WakeupException e) {
                    // WakeupException indicates that shutdown was requested
                    // If the consumer is not closed, re-throw the exception
                    if (!closed) {
                        throw e;
                    }
                }
            }
        } finally {
            consumer.close();
        }
    }

    /**
     * Process a single record idempotently.
     * This method should be idempotent - processing the same record multiple times
     * should have the same effect as processing it once.
     *
     * @param record the ConsumerRecord to process
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        // Process the inventory update message
        // Example: Parse and update inventory based on the record key and value
        String key = record.key();
        String value = record.value();

        // Idempotent processing: this operation should be repeatable safely
        // In a real implementation, you might use the record key as an idempotency key
        // stored in your database to prevent duplicate processing
        System.out.printf("Processing inventory update - Key: %s, Value: %s, Partition: %d, Offset: %d%n",
                          key, value, record.partition(), record.offset());
    }

    /**
     * Gracefully shutdown the consumer.
     * This method can be called from another thread to trigger shutdown.
     */
    public void shutdown() {
        closed = true;
        // wakeup() is thread-safe and will interrupt the poll() call
        consumer.wakeup();
    }

    public static void main(String[] args) {
        String bootstrapServers = "localhost:9092";
        String groupId = "inventory-consumer-group";

        if (args.length >= 2) {
            bootstrapServers = args[0];
            groupId = args[1];
        }

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers, groupId);

        // Setup shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down consumer...");
            inventoryConsumer.shutdown();
        }));

        // Start consuming
        inventoryConsumer.start();
    }
}

