     * should have the same effect as processing it once.
     *
     * @param record the ConsumerRecord to process
     */
    private void processRecord(ConsumerRecord<String, String> record) {
        // Process the inventory update message
        // Example: Parse and update inventory based on the record key and value
        String key = record.key();
        String value = record.value();

        // Idempotent processing: this operation should be repeatable safely
        // In a real implementation, you might use the record key as an idempotency key
        // stored in your database to prevent duplicate processing
        System.out.printf("Processing inventory update - Key: %s, Value: %s, Partition: %d, Offset: %d%n",
                          key, value, record.partition(), record.offset());
    }

    /**
     * Gracefully shutdown the consumer.
     * This method can be called from another thread to trigger shutdown.
     */
    public void shutdown() {
        closed = true;
        // wakeup() is thread-safe and will interrupt the poll() call
        consumer.wakeup();
    }

    public static void main(String[] args) {
        String bootstrapServers = "localhost:9092";
        String groupId = "inventory-consumer-group";

        if (args.length >= 2) {
            bootstrapServers = args[0];
            groupId = args[1];
        }

        InventoryConsumer inventoryConsumer = new InventoryConsumer(bootstrapServers, groupId);

        // Setup shutdown hook for graceful shutdown
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down consumer...");
            inventoryConsumer.shutdown();
        }));

        // Start consuming
        inventoryConsumer.start();
    }
}

